   ```javascript
   // Adding camera shake effect
   function cameraShake() {
       const originalPosition = camera.position;
       let shakeIntensity = 10; // pixels

       for (let i = 0; i < 10; i++) {
           setTimeout(() => {
               camera.position.x = originalPosition.x + (Math.random() * shakeIntensity - shakeIntensity / 2);
               camera.position.y = originalPosition.y + (Math.random() * shakeIntensity - shakeIntensity / 2);
           }, i * 20);
       }

